import * as React from 'react';
import type { HookSharedOptions } from '../util';
import { isFunction } from '../util';
import { useMountedState } from './useMountedState';
import { isClient } from '@universe-design/react-utilities';

export function getDefaultMediaMatches(rawQuery: string) {
  if (!isClient()) {
    return false;
  }
  return window.matchMedia(rawQuery).matches;
}

export const useMedia = (
  rawQuery: string,
  { onChange, skipped = false }: { onChange?: () => void } & HookSharedOptions = {},
) => {
  const [state, setState] = React.useState(() => getDefaultMediaMatches(rawQuery));
  const isMounted = useMountedState();

  React.useEffect(() => {
    if (skipped) {
      return;
    }

    const mediaQueryList = window.matchMedia(rawQuery);

    const handleChange = () => {
      if (!isMounted()) {
        return;
      }
      setState(Boolean(mediaQueryList.matches));
      isFunction(onChange) && onChange();
    };

    mediaQueryList.addListener(handleChange);
    setState(mediaQueryList.matches);

    return () => {
      mediaQueryList.removeListener(handleChange);
    };
  }, [isMounted, onChange, rawQuery, skipped]);

  return state;
};
